#include<bits/stdc++.h>#include<ext/pb_ds/assoc_container.hpp>#include<ext/pb_ds/tree_policy.hpp>using namespace std;using namespace __gnu_pbds; #define ll long long#define nl "\n"#define FASTER ios_base::sync_with_stdio(0); cin.tie(0); cout.tie(0);template <typename T> using ordered_set = tree<T,null_type, less<T>, rb_tree_tag, tree_order_statistics_node_update>; const ll N = 1e5+10;const ll mod = 1e9+7;const ll INF = 1e9+10; void solve(){    ll r,g,b;    cin>>r>>g>>b;    vector<pair<ll,char>> cnt = {{r,'R'},{g,'G'},{b,'B'}};    string ans = "";    ll n = 0;   // size of ans    while(true){        sort(cnt.rbegin(), cnt.rend());        ll pick = -1;   // which idx we are picking        for(int j=0; j<3; j++){            if(cnt[j].first==0) continue;             char c = cnt[j].second;            // the given condition            if(n>=1 and c==ans[n-1]) continue;            if(n>=3 and c==ans[n-3]) continue;            if(pick==-1){   // if not pick anything before then just pick it & continue                pick = j;                continue;            }             // handle edge case, have same freq            if(n>=2 and cnt[pick].first==cnt[j].first and cnt[j].second==ans[n-2]){                pick = j;            }        }         if(pick==-1) break;        ans.push_back(cnt[pick].second);        n++;  // inc the size of string        cnt[pick].first--;   // dec the freq    }    cout<<ans<<nl;} int main(){    FASTER    ll t;    cin>>t;    while(t--){        solve();    }}                   /*Starting format will be: "XYZ" or "XYX", here, X is the highest freq char.Then what will be next:For "XYZ": The color of next one is must be equal to the second one. "XYZY" then "XYZYZY". Now that "YZY" part isequal to the format "XYX". For "XYX": The next color must be Y/Z, we can't pick X here. Then it will be: "XYXY" or "XYXZ". *Y/Z which one will be picked: We will pick highest freq char to add next. *Why X is highest freq char & For "XYX" the next one is highest freq char?- Because we need to use highest freq char in optimal way. If we not use use it in optimal way then in last it will be"XXXX...", which doesn't obey the condition. ***We choose highest freq char in each step because if there is a soln exist without the highest freq option then there is always a alternative way of soln with the highest freq option.    Example: r=3, g=2, b=2    Lets start with the lowest freq char: "GBRBRGR" - this is the valid soln.    Here, the highest freq char coming to the last.    For this approach there is another valid soln of it which is the soln of highest freq option.    * Reverse the string - "RGRBRBG" - This is also the valid soln of highest freq option.So, better is always pick the highest remaining freq char to add next. The Edge Case is two chars have same freq. If any two colors cnt is equal then the previous 2 index's (i-2) color will getthe high priority because its doesn't conflict with the given condition. This method is known as Exchange Argument Technique in greedy.TC: O(n)*/